// Inside a ViewModel
val forecasts: Flow<List<ForecastRecord>> = dao.observeAllForecasts()

// Inside a Composable
val forecastList by viewModel.forecasts.collectAsState(initial = emptyList())
LazyColumn {
    items(forecastList) { record -> ForecastRow(record) }
}

@Database(entities = [ForecastRecord::class], version = 1)
abstract class AppDatabase : RoomDatabase() {
    abstract fun forecastDao(): ForecastDao
}
